import UIKit
import SwiftUI

// MARK: - Route

enum AppRoute: Equatable {
    case resetPassword(token: String)
}

// MARK: - Route Parsing

enum UniversalLinkParser {
    static func parse(url: URL) -> AppRoute? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else { return nil }

        let host = (components.host ?? "").lowercased()
        guard host == "myapp.com" || host == "www.myapp.com" else { return nil }

        let path = components.path.lowercased()
        guard path == "/reset-password" else { return nil }

        let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value ?? ""
        let trimmed = token.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        return .resetPassword(token: trimmed)
    }
}

// MARK: - Router

@MainActor
final class AppRouter: ObservableObject {
    @Published var route: AppRoute?

    func handle(_ url: URL) -> Bool {
        guard let route = UniversalLinkParser.parse(url: url) else { return false }
        self.route = route
        return true
    }

    func clear() {
        route = nil
    }
}

// MARK: - UIKit Entry (AppDelegate)

final class AppDelegate: NSObject, UIApplicationDelegate {
    static let router = AppRouter()

    func application(
        _ application: UIApplication,
        continue userActivity: NSUserActivity,
        restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void
    ) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL
        else { return false }

        return Task { @MainActor in
            _ = AppDelegate.router.handle(url)
        }.result.map { _ in true } ?? false
    }
}

// MARK: - SwiftUI App Entry

@main
struct MyApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var router = AppDelegate.router

    var body: some Scene {
        WindowGroup {
            RootView()
                .environmentObject(router)
        }
    }
}

// MARK: - Root Navigation

struct RootView: View {
    @EnvironmentObject private var router: AppRouter
    @State private var showReset = false
    @State private var resetToken: String = ""

    var body: some View {
        NavigationStack {
            HomeView()
                .navigationDestination(isPresented: $showReset) {
                    PasswordResetView(token: resetToken) {
                        router.clear()
                        showReset = false
                    }
                }
                .onReceive(router.$route) { route in
                    guard let route else { return }
                    switch route {
                    case .resetPassword(let token):
                        resetToken = token
                        showReset = true
                    }
                }
        }
    }
}

